import{o as e,c as r,a as i}from"./app.a612cc0f.js";const o='{"title":"vue 版本兼容性","description":"","frontmatter":{},"headers":[{"level":2,"title":"vue 2.x 兼容","slug":"vue-2-x-兼容"},{"level":2,"title":"vue2 click","slug":"vue2-click"},{"level":3,"title":"script error 跨域错误","slug":"script-error-跨域错误"},{"level":3,"title":"ios wifi Error DOM Exception 18","slug":"ios-wifi-error-dom-exception-18"}],"relativePath":"guide/vue/base.md","lastUpdated":1624619937661}',t={},c=[i('<h1 id="vue-版本兼容性"><a class="header-anchor" href="#vue-版本兼容性" aria-hidden="true">#</a> vue 版本兼容性</h1><h2 id="vue-2-x-兼容"><a class="header-anchor" href="#vue-2-x-兼容" aria-hidden="true">#</a> vue 2.x 兼容</h2><ul><li><a href="https://cli.vuejs.org/config/" target="_blank" rel="noopener noreferrer">vue.config 配置</a>.</li></ul><h2 id="vue2-click"><a class="header-anchor" href="#vue2-click" aria-hidden="true">#</a> vue2 click</h2><p>vue 3.x 与 vue 2.x 差异 Vue2.x 官方文档关于父子组件通讯的原则，父组件通过 prop 传递数据给子组件，子组件触发事件给父组件。 但父组件想在子组件上监听自己的 click 的话，需要加上 native 修饰符</p><ul><li><code>@click.native</code> 是给组件绑定原生事件</li></ul><p>vue 2.x 组件需要修饰符号</p><p><code>&lt;Icon type=&quot;icon-mima&quot; @click.native=&quot;btnEvent&quot; /&gt;</code></p><h3 id="script-error-跨域错误"><a class="header-anchor" href="#script-error-跨域错误" aria-hidden="true">#</a> script error 跨域错误</h3><p><code>script error.</code>有时也被称为跨域错误。 当网站请求并执行一个托管在第三方域名下的脚本时，就可能遇到该错误。 最常见的情形是使用 CDN 托管 JS 资源。 出于安全考虑，浏览器会刻意隐藏其他域的 JS 文件抛出的具体错误信息，这样做可以有效避免敏感信息无意中被不受控制的第三方脚本捕获。</p><ul><li><p>方法 1 添加属性 crossorigin=&quot;anonymous&quot; 不建议,此方法兼容性问题</p><p>此步骤的作用是告知浏览器以匿名方式获取目标脚本。这意味着请求脚本时不会向服务端发送潜在的用户身份信息（例如 Cookies、HTTP 证书等）。 <code>&lt;script src=&quot;http://another-domain.com/app.js&quot; crossorigin=&quot;anonymous&quot;&gt;&lt;/script&gt;</code></p></li><li><p>方法 2 添加跨域 HTTP 响应头： 注意：大部分主流 CDN 默认添加了 Access-Control-Allow-Origin 属性。 完成上述两步之后，即可通过 window.onerror 捕获跨域脚本的报错信息</p></li></ul><h3 id="ios-wifi-error-dom-exception-18"><a class="header-anchor" href="#ios-wifi-error-dom-exception-18" aria-hidden="true">#</a> ios wifi Error DOM Exception 18</h3><ul><li><p>vue 路由问题导致，wifi 弹出 ios 浏览器，不支持报错 history.pushState &amp; DOM Exception 18</p><p><a href="https://github.com/vuejs/vue-router/issues/564" target="_blank" rel="noopener noreferrer">https://github.com/vuejs/vue-router/issues/564</a><code>This is a bug related to Safari. Using history: false should fix your issue. I&#39;m closing because of inactivity. If you&#39;re still facing this problem consider opening a new issue with a reproduction</code></p></li><li><p>iPhone6 浏览器测试 log 中提示 SecurityError (DOM Exception 18)</p></li><li><p>HTML5 Web Demo 报错 (Uncaught Error: SECURITY_ERR: DOM Exception 18) 错误指向此行: History.replaceState({location:href}, &quot;&quot;, href);</p></li><li><p>DOM Exception 18 通常意味着你超过了设备允许的配额(50MB),尽管在某些环境中它是因为 Apple 删除了 WebSQL 支持(例如 WKWebView).</p></li><li><p><a href="https://github.com/pouchdb/pouchdb/issues/4234" target="_blank" rel="noopener noreferrer">https://github.com/pouchdb/pouchdb/issues/4234</a></p></li></ul>',13)];t.render=function(i,o,t,a,s,u){return e(),r("div",null,c)};export{o as __pageData,t as default};
